// âœ… REAL VALIDATION WITHOUT EXTERNAL LIBRARIES
try {
 const { email, password } = $json.body;

 // Basic validation
 if (!email || !password) {
 return {
 success: false,
 error: 'Email and password are required',
 statusCode: 400
 };
 }

 // Validate email format with native regex
 const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
 if (!emailRegex.test(email)) {
 return {
 success: false,
 error: 'Invalid email format',
 statusCode: 400
 };
 }

 // Basic rate limiting with timestamp
 const clientIP = $json.headers['x-forwarded-for'] || 'unknown';
 const rateLimitKey = `rate_limit_${clientIP}`;

 return {
 email: email.toLowerCase().trim(),
 password,
 clientIP,
 userAgent: $json.headers['user-agent'] || 'unknown',
 timestamp: new Date().toISOString()
 };

} catch (error) {
 return {
 success: false,
 error: 'Error validating input',
 statusCode: 500
 };
}

// âœ… PROCESS SUPABASE RESPONSE
try {
 const authResponse = $json;

 if (authResponse.error) {
 return {
 success: false,
 error: authResponse.error_description || 'Invalid credentials',
 statusCode: 401
 };
 }

 // Supabase returns the token directly
 const { access_token, refresh_token, user } = authResponse;

 if (!access_token || !user) {
 return {
 success: false,
 error: 'Authentication response error',
 statusCode: 500
 };
 }

 // Get additional user data from our DB
 return {
 success: true,
 user: {
 id: user.id,
 email: user.email,
 role: user.user_metadata?.role || 'seller',
 company_id: user.user_metadata?.company_id || 1,
 profile: user.user_metadata?.profile || {}
 },
 tokens: {
 accessToken: access_token,
 refreshToken: refresh_token
 },
 expiresIn: authResponse.expires_in
 };

} catch (error) {
 return {
 success: false,
 error: 'Error processing authentication',
 statusCode: 500
 };
}

// âœ… EXTRACT AND VALIDATE TOKEN (Supabase validates)
try {
 const authHeader = $json.headers.authorization;

 if (!authHeader || !authHeader.startsWith('Bearer ')) {
 return {
 success: false,
 error: 'Authorization token required',
 statusCode: 401
 };
 }

 const token = authHeader.substring(7);
 const idempotencyKey = $json.headers['idempotency-key'];

 if (!idempotencyKey) {
 return {
 success: false,
 error: 'Idempotency-key header is required',
 statusCode: 400
 };
 }

 // Extract real IP (first IP in x-forwarded-for)
 const clientIP = $json.headers['x-forwarded-for']?.split(',')[0]?.trim() || 'unknown';
 const userAgent = $json.headers['user-agent'] || 'unknown';

 return {
 token,
 saleData: $json.body,
 idempotencyKey,
 clientIP,
 userAgent
 };

} catch (error) {
 return {
 success: false,
 error: 'Error validating token',
 statusCode: 500
 };
}

try {
 const setnxResult = $('Redis - SETNX').first().json;

 // If SETNX returns OK, the key was created (did not exist)
 if (setnxResult === 'OK' || setnxResult.value === 'PROCESSING') {
 return {
 cached: false,
 proceed: true
 };
 }

 // If we get here, the key already existed
 const cachedValue = $('Redis - GET Cached').first().json.value;

 if (cachedValue === 'PROCESSING') {
 return {
 success: false,
 error: 'Request is already being processed',
 statusCode: 409
 };
 }

 return {
 cached: true,
 result: JSON.parse(cachedValue)
 };

} catch (error) {
 return {
 success: false,
 error: 'Error verifying idempotency',
 statusCode: 500
 };
}

// âœ… PROCESS SALE WITH ROBUST VALIDATION
try {
 const products = $('Verify Inventory Secure').all().map(item => item.json);
 const saleData = $json.saleData;
 const user = $json.user;

 // âœ… ROBUST INPUT DATA VALIDATION

 // Validate basic structure
 if (!saleData || typeof saleData !== 'object') {
 throw new Error('saleData must be a valid object');
 }

 // Validate items
 if (!saleData.items || !Array.isArray(saleData.items) || saleData.items.length === 0) {
 throw new Error('items must be a non-empty array');
 }

 // âœ… NEW: Validate item limits
 if (saleData.items.length > 100) {
 throw new Error('Maximum 100 items per sale');
 }

 // Validate each item individually
 for (let i = 0; i < saleData.items.length; i++) {
 const item = saleData.items[i];

 // Validate product_id
 if (!Number.isInteger(item.product_id) || item.product_id <= 0) {
 throw new Error(`Item ${i}: invalid product_id: ${item.product_id}. Must be a positive integer.`);
 }

 // Validate quantity
 if (!Number.isInteger(item.quantity) || item.quantity <= 0) {
 throw new Error(`Item ${i}: invalid quantity: ${item.quantity}. Must be a positive integer.`);
 }

 // âœ… NEW: Validate quantity range
 if (item.quantity > 10000) {
 throw new Error(`Item ${i}: Maximum quantity: 10,000 units`);
 }

 // Validate unit_price
 if (typeof item.unit_price !== 'number' || item.unit_price <= 0 || !isFinite(item.unit_price)) {
 throw new Error(`Item ${i}: invalid unit_price: ${item.unit_price}. Must be a positive finite number.`);
 }

 // âœ… NEW: Validate price range
 if (item.unit_price > 1000000) {
 throw new Error(`Item ${i}: Maximum price: $1,000,000`);
 }
 }

 // Validate customer_info
 if (!saleData.customer_info || typeof saleData.customer_info !== 'object') {
 throw new Error('customer_info is required and must be an object');
 }

 if (!saleData.customer_info.name || typeof saleData.customer_info.name !== 'string' || saleData.customer_info.name.trim() === '') {
 throw new Error('customer_info.name is required and cannot be empty');
 }

 // âœ… NEW: Sanitize name
 const sanitizeName = (name) => {
 return name
 .replace(/[<>\'"\\]/g, '') // Remove dangerous characters
 .replace(/\s+/g, ' ') // Normalize spaces
 .trim()
 .slice(0, 255); // Limit length
 };

 // Validate email if provided
 if (saleData.customer_info.email) {
 const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
 if (!emailRegex.test(saleData.customer_info.email)) {
 throw new Error('customer_info.email has invalid format');
 }
 }

 // Validate payment_method
 const validPaymentMethods = ($env.PAYMENT_METHODS || 'cash,card,transfer,check').split(',');
 if (saleData.payment_method && !validPaymentMethods.includes(saleData.payment_method)) {
 throw new Error(`invalid payment_method: ${saleData.payment_method}. Valid values: ${validPaymentMethods.join(', ')}`);
 }

 // âœ… VERIFY INVENTORY
 const inventoryCheck = {};
 for (const product of products) {
 inventoryCheck[product.id] = {
 available: product.quantity - product.reserved,
 product: product
 };
 }

 const unavailableItems = [];
 let totalAmount = 0;

 for (const item of saleData.items) {
 const inventory = inventoryCheck[item.product_id];
 if (!inventory || inventory.available < item.quantity) {
 unavailableItems.push({
 product_id: item.product_id,
 requested: item.quantity,
 available: inventory ? inventory.available : 0,
 product_name: inventory ? inventory.product.name : 'Not found'
 });
 }

 totalAmount += item.quantity * item.unit_price;
 }

 if (unavailableItems.length > 0) {
 return {
 success: false,
 error: 'Insufficient inventory',
 unavailableItems,
 statusCode: 400
 };
 }

 // âœ… CALCULATE TOTALS
 const taxRate = parseFloat($env.TAX_RATE || 0.16);
 const taxAmount = Math.round(totalAmount * taxRate * 100) / 100; // Round to 2 decimal places
 const finalTotal = Math.round((totalAmount + taxAmount) * 100) / 100;

 // Generate unique invoice number
 const timestamp = Date.now();
 const randomSuffix = Math.floor(Math.random() * 1000).toString().padStart(3, '0');
 const invoiceNumber = `F-${new Date().getFullYear()}-${timestamp.toString().slice(-6)}-${randomSuffix}`;

 return {
 company_id: user.user_metadata?.company_id || 1,
 user_id: user.id,
 customer_info: {
 name: sanitizeName(saleData.customer_info.name),
 email: saleData.customer_info.email?.trim().toLowerCase().slice(0, 255) || null,
 phone: saleData.customer_info.phone?.replace(/[^\d+\-() ]/g, '').slice(0, 20) || null
 },
 invoice_number: invoiceNumber,
 total_amount: totalAmount,
 tax_amount: taxAmount,
 final_total: finalTotal,
 payment_method: saleData.payment_method || 'cash',
 items: saleData.items,
 metadata: {
 ip: $json.clientIP,
 user_agent: $json.userAgent,
 timestamp: new Date().toISOString(),
 validation_passed: true
 }
 };

} catch (error) {
 return {
 success: false,
 error: error.message || 'Error processing sale',
 statusCode: 400,
 validation_error: true
 };
}

try {
 const result = $json;
 const processedSale = $('Process Sale Secure').first().json;

 // Validate that the function returned success
 if (!result.success || !result.sale_id) {
 return {
 success: false,
 error: result.error_message || 'Sale transaction error',
 statusCode: 500
 };
 }

 // All good, prepare response
 return {
 success: true,
 sale_id: result.sale_id,
 invoice_number: processedSale.invoice_number,
 final_total: processedSale.final_total,
 payment_method: processedSale.payment_method
 };

} catch (error) {
 return {
 success: false,
 error: error.message || 'Error validating sale result',
 statusCode: 500
 };
}

